import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void corridorAroundWall() {
        int[][] grid = {
            {0, 0, 0},
            {1, 1, 0},
            {0, 0, 0}
        };
        assertEquals(5, new Solution().shortestPath(grid));
    }

    @Test
    void unreachable_returnsMinusOne() {
        int[][] grid = {
            {0, 1},
            {1, 0}
        };
        assertEquals(-1, new Solution().shortestPath(grid));
    }

    @Test
    void singleCell() {
        int[][] grid = {{0}};
        assertEquals(1, new Solution().shortestPath(grid));
    }

    @Test
    void emptyGrid() {
        int[][] grid = {};
        assertEquals(-1, new Solution().shortestPath(grid));
    }

    @Test
    void startBlocked() {
        int[][] grid = {{1, 0}, {0, 0}};
        assertEquals(-1, new Solution().shortestPath(grid));
    }

    @Test
    void endBlocked() {
        int[][] grid = {{0, 0}, {0, 1}};
        assertEquals(-1, new Solution().shortestPath(grid));
    }

    @Test
    void openSquare_shortestIs3() {
        int[][] grid = {
            {0, 0},
            {0, 0}
        };
        assertEquals(3, new Solution().shortestPath(grid));
    }
}
